const ROOM_MAP = {
  CUBEOS: '!iXTnQsFJahUquYPDdG:matrix.example.net',
  MESHSAT: '!miZJJDwFQZDkuMcBqL:matrix.example.net',
  IFRNLLEI01PRD: '!AOMuEtXGyzGFLgObKN:matrix.example.net',
  IFRGRSKG01PRD: '!NKosBPujbWMevzHaaM:matrix.example.net'
};
const DEFAULT_ROOM = '!PVkZvHgyrtBVEbgpRt:matrix.example.net';

const stdout = $input.first().json.stdout || '';
const stderr = $input.first().json.stderr || '';
const webhookData = $('Session End Webhook').first().json;
const issueId = webhookData.body?.issueId || '';
const issueTitle = webhookData.body?.issueTitle || '';
const sessionId = webhookData.body?.sessionId || '';

const prefix = (issueId || '').split('-')[0];
const targetRoom = ROOM_MAP[prefix] || DEFAULT_ROOM;

const output = stdout.trim() || stderr.trim();

let summary, lesson = '';
try {
  const parsed = JSON.parse(output);
  const fullResult = parsed.result || '';
  // Extract LESSON: line if present
  const lessonMatch = fullResult.match(/LESSON:\s*(.+?)(?:\n|$)/i);
  if (lessonMatch && lessonMatch[1].trim().toLowerCase() !== 'none') {
    lesson = lessonMatch[1].trim();
  }
  // Summary is everything before LESSON:
  const lessonIdx = fullResult.indexOf('LESSON:');
  summary = lessonIdx > 0 ? fullResult.substring(0, lessonIdx).trim() : fullResult;
} catch (e) {
  summary = output ? 'Error getting summary: ' + output.substring(0, 500) : 'No summary available (session may have expired)';
}

// Sanitize literal \n sequences to real newlines (prevents double-escaping in YT comments)
summary = summary.replace(/\\n/g, '\n');

return [{ json: { summary, lesson, issueId, issueTitle, sessionId, targetRoom } }];

const issueId = $('Parse Summary').first().json.issueId || '—';
const state = issueId !== '—' ? 'To Verify' : '—';

const W = 54;
const cw = W - 2;

const artLines = [
  ' ██████╗██╗  ██╗ █████╗ ████████╗ ██████╗ ██████╗ ███████╗',
  '██╔════╝██║  ██║██╔══██╗╚══██╔══╝██╔═══██╗██╔══██╗██╔════╝',
  '██║     ███████║███████║   ██║   ██║   ██║██████╔╝███████╗',
  '██║     ██╔══██║██╔══██║   ██║   ██║   ██║██╔═══╝ ╚════██║',
  '╚██████╗██║  ██║██║  ██║   ██║   ╚██████╔╝██║     ███████║',
  ' ╚═════╝╚═╝  ╚═╝╚═╝  ╚═╝   ╚═╝    ╚═════╝ ╚═╝     ╚══════╝'
];

const maxArt = Math.max(...artLines.map(l => l.length));
const boxW = Math.max(W, maxArt + 4);
const boxCw = boxW - 2;

const pad = (s) => s + ' '.repeat(Math.max(0, boxCw - s.length));
const center = (s) => {
  const left = Math.floor((boxCw - s.length) / 2);
  return ' '.repeat(left) + s + ' '.repeat(boxCw - s.length - left);
};

const sep = [
  '╔' + '═'.repeat(boxW) + '╗',
  ...artLines.map(l => '║ ' + pad(l) + ' ║'),
  '╠' + '═'.repeat(boxW) + '╣',
  '║ ' + center('SESSION COMPLETE') + ' ║',
  '╠' + '═'.repeat(boxW) + '╣',
  '║ ' + pad('Issue : ' + issueId) + ' ║',
  '║ ' + pad('State : ' + state) + ' ║',
  '╚' + '═'.repeat(boxW) + '╝'
].join('\n');

const matrixBody = JSON.stringify({
  msgtype: 'm.text',
  body: sep,
  format: 'org.matrix.custom.html',
  formatted_body: '<pre><code>' + sep + '</code></pre>'
});

return [{ json: { matrixBody } }];

const issueId = $('Parse Summary').first().json.issueId || '';
const summary = $('Parse Summary').first().json.summary || '';

const plainBody = (issueId ? 'Session ended for ' + issueId + '. State set to To Verify.' : 'Session ended (no active issue).') + '\n\nSummary:\n' + summary;

// Improved HTML formatting
let htmlSummary = summary
  .replace(/&/g, '&amp;')
  .replace(/</g, '&lt;')
  .replace(/>/g, '&gt;')
  .replace(/\*\*\*(.+?)\*\*\*/g, '<strong><em>$1</em></strong>')
  .replace(/\*\*(.+?)\*\*/g, '<strong>$1</strong>')
  .replace(/\*(.+?)\*/g, '<em>$1</em>')
  .replace(/`([^`]+)`/g, '<code>$1</code>')
  .replace(/^- (.+)$/gm, '<li>$1</li>')
  .replace(/(<li>.*<\/li>)/gs, '<ul>$1</ul>')
  .replace(/<\/ul>\s*<ul>/g, '')
  .replace(/\n/g, '<br>');

const htmlBody = (issueId
  ? '<p><strong>Session ended</strong> for <code>' + issueId + '</code> — state set to <em>To Verify</em></p>'
  : '<p>Session ended (no active issue).</p>')
  + '<hr>'
  + '<p>' + htmlSummary + '</p>';

const matrixBody = JSON.stringify({
  msgtype: 'm.notice',
  body: plainBody,
  format: 'org.matrix.custom.html',
  formatted_body: htmlBody
});

return [{ json: { matrixBody } }];

